const today = new Date().toISOString().slice(0,10).replace(/-/g,'');
const sd = $getWorkflowStaticData('global');
sd.events = { futbol: [], nba: [], mlb: [], nhl: [], nfl: [] };
sd.hipismoText = '';
sd.date = new Date().toISOString().slice(0,10);

const sports = [
  { sport: 'futbol', url: `https://site.api.espn.com/apis/site/v2/sports/soccer/eng.1/scoreboard?dates=${today}`, isHtml: false },
  { sport: 'futbol', url: `https://site.api.espn.com/apis/site/v2/sports/soccer/esp.1/scoreboard?dates=${today}`, isHtml: false },
  { sport: 'futbol', url: `https://site.api.espn.com/apis/site/v2/sports/soccer/ger.1/scoreboard?dates=${today}`, isHtml: false },
  { sport: 'futbol', url: `https://site.api.espn.com/apis/site/v2/sports/soccer/ita.1/scoreboard?dates=${today}`, isHtml: false },
  { sport: 'futbol', url: `https://site.api.espn.com/apis/site/v2/sports/soccer/fra.1/scoreboard?dates=${today}`, isHtml: false },
  { sport: 'futbol', url: `https://site.api.espn.com/apis/site/v2/sports/soccer/bra.1/scoreboard?dates=${today}`, isHtml: false },
  { sport: 'futbol', url: `https://site.api.espn.com/apis/site/v2/sports/soccer/arg.1/scoreboard?dates=${today}`, isHtml: false },
  { sport: 'futbol', url: `https://site.api.espn.com/apis/site/v2/sports/soccer/mex.1/scoreboard?dates=${today}`, isHtml: false },
  { sport: 'nba',    url: `https://site.api.espn.com/apis/site/v2/sports/basketball/nba/scoreboard?dates=${today}`, isHtml: false },
  { sport: 'mlb',    url: `https://site.api.espn.com/apis/site/v2/sports/baseball/mlb/scoreboard?dates=${today}`, isHtml: false },
  { sport: 'nhl',    url: `https://site.api.espn.com/apis/site/v2/sports/hockey/nhl/scoreboard?dates=${today}`, isHtml: false },
  { sport: 'nfl',    url: `https://site.api.espn.com/apis/site/v2/sports/football/nfl/scoreboard?dates=${today}`, isHtml: false },
  { sport: 'hipismo',url: 'https://www.macacohipico.com.ve', isHtml: true }
];
return sports.map(s => ({ json: s }));

const sd = $getWorkflowStaticData('global');
const orig = $('SplitInBatches').item.json;
const sport  = orig.sport;
const isHtml = orig.isHtml;
const resp   = $input.first().json;

const normalizeEvent = (e) => {
  const comp = e.competitions?.[0];
  if (!comp) return null;
  const home = comp.competitors?.find(c => c.homeAway === 'home');
  const away = comp.competitors?.find(c => c.homeAway === 'away');
  return {
    id: e.id || '',
    evento: `${away?.team?.displayName || '?'} @ ${home?.team?.displayName || '?'}`,
    local: home?.team?.displayName || '?',
    visitante: away?.team?.displayName || '?',
    localRecord: home?.records?.[0]?.summary || 'N/D',
    visitanteRecord: away?.records?.[0]?.summary || 'N/D',
    estado: comp.status?.type?.shortDetail || comp.status?.type?.name || 'Programado',
    inProgress: comp.status?.type?.state === 'in',
    marcadorLocal: home?.score || '-',
    marcadorVisitante: away?.score || '-',
    fecha: comp.startDate ? new Date(comp.startDate).toLocaleString('es-ES') : 'N/D',
    liga: comp.league?.abbreviation || '',
    venue: comp.venue?.fullName || ''
  };
};

if (isHtml) {
  let html = resp.data || JSON.stringify(resp);
  let text = html
    .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi,' ')
    .replace(/<style\b[^<]*(?:(?!<\/style>)<[^<]*)*<\/style>/gi,' ')
    .replace(/<[^>]+>/g,' ').replace(/&nbsp;/g,' ').replace(/\s+/g,' ').trim();
  sd.hipismoText = (sd.hipismoText + ' ' + text).trim().substring(0, 5000);
} else {
  const events = (resp.events || []).map(normalizeEvent).filter(Boolean);
  if (!sd.events[sport]) sd.events[sport] = [];
  sd.events[sport].push(...events);
}

return [{ json: { sport, done: true } }];

const sd = $getWorkflowStaticData('global');
const ev = sd.events || {};

const toText = (events) => (events || []).slice(0,20)
  .map(e => `${e.evento} | ${e.visitanteRecord} vs ${e.localRecord} | ${e.estado}`)
  .join('\n') || 'Sin partidos hoy';

const sysPrompt = `Eres un analista deportivo experto. Analiza los partidos y genera predicciones.
Devuelve SOLO un JSON con esta estructura exacta:
{
  "futbol":[{"Evento":"A vs B","Liga":"...","Prediccion":"1-0","Probabilidad":70,"Riesgo":"Bajo","Justificacion":"..."}],
  "nba":[{"Evento":"...","Liga":"NBA","Prediccion":"112-105","Probabilidad":65,"Riesgo":"Medio","Justificacion":"..."}],
  "mlb":[{"Evento":"...","Liga":"MLB","Prediccion":"6-4","Probabilidad":60,"Riesgo":"Medio","Justificacion":"..."}],
  "nhl":[{"Evento":"...","Liga":"NHL","Prediccion":"3-2","Probabilidad":58,"Riesgo":"Medio","Justificacion":"..."}],
  "nfl":[{"Evento":"...","Liga":"NFL","Prediccion":"27-24","Probabilidad":62,"Riesgo":"Bajo","Justificacion":"..."}],
  "hipismo":[{"Carrera":"1ra","Caballo1":"...","Prob1":45,"Caballo2":"...","Prob2":30,"Justificacion":"..."}]
}
Para cada deporte selecciona maximo 8 items. SOLO JSON valido, sin markdown.`;

const userContent = `FUTBOL:\n${toText(ev.futbol)}\n\nNBA:\n${toText(ev.nba)}\n\nMLB:\n${toText(ev.mlb)}\n\nNHL:\n${toText(ev.nhl)}\n\nNFL:\n${toText(ev.nfl)}\n\nHIPISMO (texto web):\n${(sd.hipismoText||'').substring(0,2000)}`;

return [{ json: {
  date: sd.date || new Date().toISOString().slice(0,10),
  events: ev,
  hipismoText: sd.hipismoText || '',
  messages: [
    { role: 'system', content: sysPrompt },
    { role: 'user',   content: userContent }
  ]
}}];

const aiResp = $input.first().json;
const prev   = $('Construir Input para IA').first().json;
const fechaReporte = prev.date || new Date().toISOString().slice(0,10);

let predictions = { futbol:[], nba:[], mlb:[], nhl:[], nfl:[], hipismo:[] };
try {
  let content = aiResp.choices[0].message.content;
  content = content.replace(/```json/g,'').replace(/```/g,'').trim();
  const b1 = content.indexOf('{'), b2 = content.lastIndexOf('}');
  if (b1 !== -1 && b2 !== -1) content = content.substring(b1, b2+1);
  predictions = { ...predictions, ...JSON.parse(content) };
} catch(e) {
  predictions._parseError = e.message;
}

const sports = ['futbol','nba','mlb','nhl','nfl'];
for (const s of sports) {
  if (Array.isArray(predictions[s])) {
    predictions[s] = predictions[s].map(p => ({ ...p, Fecha_Reporte: fechaReporte }));
  }
}

const allPreds = sports.flatMap(s => (predictions[s]||[]).map(p => ({...p, _deporte: s})));
const destacadas = allPreds.filter(p => Number(p.Probabilidad) > 55)
  .sort((a,b) => Number(b.Probabilidad)-Number(a.Probabilidad));
const top3 = destacadas.slice(0,3);

return [{ json: {
  date: fechaReporte,
  generatedAt: new Date().toISOString(),
  events: prev.events,
  predictions,
  destacadas,
  top3
}}];
